(()=>{window.Alpine={start(){document.querySelectorAll("[x-data]").forEach((e)=>{let t=false;e.querySelectorAll("[x-on\\:click]").forEach((n)=>n.addEventListener("click",()=>{t=!t;e.querySelectorAll("[x-show]").forEach((o)=>{o.style.display=t?"":"none"})}));e.querySelectorAll("[x-show]").forEach((n)=>{n.style.display="none"})})}};document.addEventListener("DOMContentLoaded",()=>window.Alpine.start())})();
